document.addEventListener("DOMContentLoaded",function(){function setupMenuToggle(){const modalTriggers=document.querySelectorAll(".modal-trigger");modalTriggers.forEach(trigger=>{trigger.addEventListener("click",function(){const targetId=this.getAttribute("data-target");const targetElement=document.getElementById(targetId);this.classList.toggle("opened");targetElement.classList.toggle("opened");document.body.classList.toggle("menu-open")})});document.addEventListener("keydown",function(e){if(e.key==="Escape"){const openedMenus=document.querySelectorAll(".header-menu-wrapper.opened");const openedToggles=document.querySelectorAll(".header-toggle.opened");openedMenus.forEach(menu=>menu.classList.remove("opened"));openedToggles.forEach(toggle=>toggle.classList.remove("opened"));document.body.classList.remove("menu-open")}});if(!document.querySelector("style#menu-styles")){const styleEl=document.createElement("style");styleEl.id="menu-styles";styleEl.textContent="body.menu-open { overflow: hidden; }";document.head.appendChild(styleEl)}}setupMenuToggle()});